// Extract and validate lead data
const body = Object.assign({}, $json["body"] || {});
const requiredFields = ['name', 'email', 'phone'];
const missing = requiredFields.filter(field => !body[field]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Normalize data
const leadData = {
  firstName: body.name.split(' ')[0] || '',
  lastName: body.name.split(' ').slice(1).join(' ') || '',
  email: body.email.toLowerCase().trim(),
  phone: body.phone.replace(/[^0-9+]/g, ''), // Keep only digits and +
  source: body.source || 'website_form',
  interests: Array.isArray(body.interests) ? body.interests : [body.interests].filter(Boolean),
  message: body.message || '',
  createdAt: new Date().toISOString()
};

return [{ json: leadData }];

