// Extract customer ID from response
const customerId = $json["id"] || $json["customer_id"];
if (!customerId) {
  throw new Error('Customer ID not found in response');
}

return [{
  json: {
    customerId: customerId,
    leadData: $json
  }
}];

// Process each interest
const interests = $json["leadData"]["interests"] || [];
return interests.map(interest => ({
  json: {
    customerId: $json["customerId"],
    interest: interest
  }
}));

// Send welcome email/SMS
// This would integrate with email/SMS services
// For now, we'll just log the action
return [{ json: {
  action: 'welcome_message_sent',
  customerId: $json["customerId"],
  timestamp: new Date().toISOString(),
  message: `Welcome ${$json["leadData"]["firstName"]}! We'll be in touch shortly.`
} }];

// Assign to agent based on workload or specialty
